```typescript
function solve(n: number, edges: number[][]): number {
    const adj: Array<Array<[number, number, number]>> = new Array(n).fill(0).map(() => []);
    for (const [u, v, s, e] of edges) {
        adj[u].push([v, s, e]);
    }

    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;

    class PriorityQueue {
        private heap: [number, number][];
        constructor() {
            this.heap = [];
        }
        push(value: [number, number]) {
            this.heap.push(value);
            this.heapifyUp();
        }
        pop(): [number, number] | undefined {
            if (this.heap.length === 0) return undefined;
            const result = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            this.heapifyDown();
            return result;
        }
        private heapifyUp() {
            let index = this.heap.length - 1;
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[index][0] < this.heap[parentIndex][0]) {
                    [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                    index = parentIndex;
                } else {
                    break;
                }
            }
        }
        private heapifyDown() {
            let index = 0;
            while (index < this.heap.length) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) {
                    smallest = left;
                }
                if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) {
                    smallest = right;
                }
                if (smallest !== index) {
                    [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                    index = smallest;
                } else {
                    break;
                }
            }
        }
        get size(): number {
            return this.heap.length;
        }
    }

    const pq = new PriorityQueue();
    pq.push([0, 0]);

    while (pq.size > 0) {
        const [currentTime, u] = pq.pop()!;
        if (u === n - 1) {
            return currentTime;
        }
        if (currentTime > dist[u]) {
            continue;
        }
        for (const [v, s, e] of adj[u]) {
            const possibleTime = Math.max(currentTime, s);
            if (possibleTime <= e) {
                const newTime = possibleTime + 1;
                if (newTime < dist[v]) {
                    dist[v] = newTime;
                    pq.push([newTime, v]);
                }
            }
        }
    }

    return -1;
}
